// src/components/Footer.jsx
import { personal } from '../data/portfolio';

export default function Footer() {
  return (
    <footer style={s.footer}>
      <span style={s.copy}>© {new Date().getFullYear()} {personal.name}. All rights reserved.</span>
      <div style={s.links}>
        <a href={`mailto:${personal.contact.email}`} style={s.link}>Email</a>
        <a href={personal.contact.linkedin} target="_blank" rel="noreferrer" style={s.link}>LinkedIn</a>
        <a href={personal.contact.portfolio} target="_blank" rel="noreferrer" style={s.link}>Portfolio</a>
      </div>
    </footer>
  );
}

const s = {
  footer: {
    background: 'var(--bg)',
    borderTop: '1px solid var(--border)',
    padding: '28px 5%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    fontSize: 13,
    color: 'var(--text3)',
  },
  copy:  {},
  links: { display: 'flex', gap: 24 },
  link:  { color: 'var(--text3)', textDecoration: 'none', transition: 'color 0.2s' },
};
